// Auto-generated by vitest-mobile — do not edit.
const path = require('node:path');
const fs = require('node:fs');
const { createRequire } = require('node:module');

const HARNESS_DIR = '{{HARNESS_DIR}}';
const PROJECT_ROOT = '{{PROJECT_ROOT}}';

// A stable real path inside the harness project. Its containing directory
// is used as the anchor for both Node's createRequire walk-up (below) and
// Metro's resolveRequest hierarchical lookup (further down). `package.json`
// is guaranteed to exist after harness scaffold, and using a real file makes
// the intent clearer than a made-up `_vitest-mobile-anchor.js` filename.
const HARNESS_ANCHOR = path.join(HARNESS_DIR, 'package.json');

const harnessReq = createRequire(HARNESS_ANCHOR);
// Hardcoded: @react-native/metro-config is a guaranteed RN-template devDep
// installed during harness scaffolding. A missing module here means the
// scaffold is corrupt; the clean MODULE_NOT_FOUND is the right signal.
const { getDefaultConfig } = harnessReq('@react-native/metro-config');

// Stubs for Node built-ins and Vite/Vitest internals that `vitest/worker`
// statically imports. On Hermes these modules don't exist; the stubs keep
// module-top evaluation safe (and provide the handful of real runtime
// behaviours Vitest / pathe / etc. rely on — e.g. `node:path` aliases to
// `pathe`, `pathToFileURL` returns a URL-ish object).
//
// For each name in STUBBED_MODULES, we look for a dedicated stub at the
// derived path (`node:fs/promises` → `stubs/node/fs/promises.js`,
// `vite/module-runner` → `stubs/vite/module-runner.js`, etc.). If none
// exists, the module resolves to `empty.js` (default `{}`, no named
// exports). Adding a new no-op stub is therefore a one-line change —
// just append the module name here. See
// packages/vitest-mobile/src/metro/vitest-stubs/README.md.
//
// Anchor the stubs lookup at PROJECT_ROOT, NOT at HARNESS_DIR. The cached
// harness's `node_modules/vitest-mobile` is a `file:`-installed symlink
// pointing at whichever workspace first built the cache — when a second
// workspace shares the cache (same RN version, same native modules, same
// vitest-mobile version → same cache key), following that symlink lands
// `STUBS_DIR` outside Metro's projectRoot + watchFolders, and the resolver
// fails with "Failed to get the SHA-1 for: …/empty.js" because the file
// isn't in Metro's in-memory file map. Resolving from PROJECT_ROOT keeps
// the stubs inside the active workspace's tree where Metro can see them,
// and is safe because the cache key includes the vitest-mobile version
// (`getHarnessVersion(options.packageRoot)`) — the workspace's stubs are
// guaranteed to match the harness's vitest-mobile version on every run.
const projectReq = createRequire(path.join(PROJECT_ROOT, 'package.json'));
const VITEST_MOBILE_ROOT = path.dirname(projectReq.resolve('vitest-mobile/package.json'));
const STUBS_DIR = path.join(VITEST_MOBILE_ROOT, 'src', 'metro', 'vitest-stubs');
const EMPTY_STUB = path.join(STUBS_DIR, 'empty.js');
const STUBBED_MODULES = new Set([
  // Node built-ins
  'node:module',
  'node:url',
  'node:path',
  'node:fs',
  'node:fs/promises',
  'node:vm',
  'node:async_hooks',
  'node:perf_hooks',
  'node:timers',
  'node:timers/promises',
  'node:util',
  'node:assert',
  'node:v8',
  'node:console',
  'node:process',
  'node:stream',
  'node:events',
  'node:buffer',
  'node:worker_threads',
  // Vite internals
  'vite/module-runner',
  // Optional Vitest environment packages — dynamically imported by the
  // environments chunk but never reached on device.
  '@edge-runtime/vm',
  'happy-dom',
  'jsdom',
  // OpenTelemetry API — gated behind traces.enabled (we pass enabled:false),
  // but `import('@opentelemetry/api')` is a string literal so Metro tries
  // to resolve it at bundle time.
  '@opentelemetry/api',
]);
const STUB_PATHS = (() => {
  const map = new Map();
  for (const name of STUBBED_MODULES) {
    // `node:fs/promises` → `node/fs/promises`; `vite/module-runner` →
    // `vite/module-runner`; `happy-dom` → `happy-dom`; etc.
    const rel = name.replace(':', '/') + '.js';
    const specific = path.join(STUBS_DIR, rel);
    map.set(name, fs.existsSync(specific) ? specific : EMPTY_STUB);
  }
  return map;
})();

const config = getDefaultConfig(PROJECT_ROOT);

// Include the harness project in Metro's watched tree. Metro's resolver
// uses an in-memory file map built from projectRoot + watchFolders, and
// `fileSystemLookup` only considers files inside that map to "exist" —
// even though we pin harness-anchored resolutions via `resolveRequest`
// below, the default resolver still needs the harness node_modules to
// be part of the file map for the physical files to be visible.
config.watchFolders = [...(config.watchFolders || []), HARNESS_DIR];

const HARNESS_PINNED = new Set([
  'react',
  'react-native',
  'react-native-safe-area-context',
  // Babel runtime helpers — injected by the transformer into every transformed file.
  '@babel/runtime',
  // vitest-mobile runtime deps — only installed in the harness tree (via vitest/chai/etc.),
  // not in the user's workspace root.
  'chai',
  'flatted',
  'pathe',
  'signalium',
  '@shopify/restyle',
  '@vitest/expect',
  '@vitest/runner',
  '@vitest/utils',
]);
function isHarnessPinned(name) {
  if (HARNESS_PINNED.has(name)) return true;
  for (const pkg of HARNESS_PINNED) {
    if (name === pkg || name.startsWith(pkg + '/')) return true;
  }
  return name.startsWith('@react-native/');
}

const prevResolveRequest = config.resolver && config.resolver.resolveRequest;
const HARNESS_DIR_PREFIX = HARNESS_DIR + path.sep;

// The generated entry file (index.<platform>.js) and metro.config.cjs live in
// the output dir (`.vitest-mobile/`), which is gitignored so generated files
// aren't committed. Watchman respects `.gitignore` and therefore excludes that
// dir from Metro's in-memory file map — so the default resolver reports
// "None of these files exist" for the bundle entry even though it's on disk.
// `resolveOnDisk` is a narrow fallback that resolves a module to a real file
// under the output dir by checking the filesystem directly, bypassing the file
// map. It only ever returns paths inside OUTPUT_DIR, so it can't mask real
// resolution failures elsewhere in the tree.
const OUTPUT_DIR = path.join(PROJECT_ROOT, '.vitest-mobile');
const OUTPUT_DIR_PREFIX = OUTPUT_DIR + path.sep;

function resolveOnDisk(moduleName, originModulePath, platform) {
  const originDir =
    originModulePath && path.extname(originModulePath)
      ? path.dirname(originModulePath)
      : originModulePath || PROJECT_ROOT;
  const base = path.resolve(originDir, moduleName);
  const candidates = [
    base + '.' + platform + '.js',
    base + '.js',
    base + '.json',
    path.join(base, 'index.' + platform + '.js'),
    path.join(base, 'index.js'),
  ];
  for (const candidate of candidates) {
    if (candidate.startsWith(OUTPUT_DIR_PREFIX) && fs.existsSync(candidate)) {
      return candidate;
    }
  }
  return null;
}

config.resolver = Object.assign({}, config.resolver, {
  resolveRequest(ctx, moduleName, platform) {
    // Redirect stubbed modules (node:*, Vite/Vitest internals, optional
    // env packages, OpenTelemetry) to the corresponding on-disk stub.
    // Hashed Vitest chunks (`coverage.<hash>.js`, `nativeModuleRunner.<hash>.js`)
    // with non-literal `import(expr)` calls are NOT handled here —
    // `vitest-compat-plugin` rewrites those to `Promise.reject(...)` at
    // parse time, so they bundle fine without chunk-level stubs.
    const stubPath = STUB_PATHS.get(moduleName);
    if (stubPath) {
      return { type: 'sourceFile', filePath: stubPath };
    }
    if (isHarnessPinned(moduleName)) {
      // Only rewrite originModulePath when the request comes from OUTSIDE
      // the harness tree. This pins user-code imports of harness-pinned
      // modules, but preserves Node's nested node_modules resolution for
      // imports that already originate within the harness tree (e.g.
      // react-native's own Libraries/Lists/FlatList.js importing
      // @react-native/virtualized-lists, which may be installed at
      // react-native/node_modules/@react-native/virtualized-lists due to
      // version conflicts).
      const originInHarness =
        typeof ctx.originModulePath === 'string' && ctx.originModulePath.startsWith(HARNESS_DIR_PREFIX);

      if (originInHarness) {
        // Request is already inside the harness tree; let the default
        // resolver do its normal nested-node_modules walk from that origin.
        return ctx.resolveRequest(ctx, moduleName, platform);
      }
      // Request is from outside the harness (user code); rewrite the
      // origin so Metro's default resolver starts from inside the harness.
      return ctx.resolveRequest(Object.assign({}, ctx, { originModulePath: HARNESS_ANCHOR }), moduleName, platform);
    }
    try {
      if (prevResolveRequest) {
        return prevResolveRequest(ctx, moduleName, platform);
      }
      return ctx.resolveRequest(ctx, moduleName, platform);
    } catch (err) {
      // Disk fallback for generated files under .vitest-mobile/ that
      // watchman excluded from the file map (see resolveOnDisk comment).
      const diskPath = resolveOnDisk(moduleName, ctx.originModulePath, platform);
      if (diskPath) {
        return { type: 'sourceFile', filePath: diskPath };
      }
      throw err;
    }
  },
});

module.exports = config;
